**阶段 1: 创建集成层 (2小时)**

```typescript
// src/dashboard/integration/iteration-integration.ts

import { IterationService, AgentService, RealtimeService } from '../server';

export class IterationIntegration {
  private iterationService: IterationService;
  private agentService: AgentService;
  private realtimeService: RealtimeService;
  private enabled: boolean = false;

  constructor() {
    // 延迟加载，避免 Dashboard 未启动时出错
    try {
      const services = require('../server').getServices();
      this.iterationService = services.iterationService;
      this.agentService = services.agentService;
      this.realtimeService = services.realtimeService;
      this.enabled = true;
    } catch (error) {
      console.warn('[IterationIntegration] Dashboard not available');
      this.enabled = false;
    }
  }

  /**
   * 迭代开始
   */
  async onIterationStart(iterationNumber: number, requirement: string) {
    if (!this.enabled) return;

    const iteration = this.iterationService.create({
      iterationNumber,
      status: 'running',
      requirement,
      startedAt: new Date()
    });

    // 广播到所有连接的客户端
    this.realtimeService.broadcastIterationStatusChange({
      iterationId: iteration.id,
      iterationNumber,
      status: 'running',
      timestamp: new Date()
    });

    return iteration.id;
  }

  /**
   * Agent 开始执行
   */
  async onAgentStart(iterationId: number, agentName: string, task: string) {
    if (!this.enabled) return;

    const agentState = this.agentService.createState({
      iterationId,
      agentName,
      status: 'running',
      currentTask: task,
      startedAt: new Date()
    });

    // 广播 Agent 状态
    this.realtimeService.broadcastAgentStatusChange({
      iterationId,
      agentName,
      status: 'running',
      currentTask: task,
      timestamp: new Date()
    });

    return agentState.id;
  }

  /**
   * Agent 执行完成
   */
  async onAgentComplete(
    iterationId: number,
    agentName: string,
    result: string,
    executionTime: number
  ) {
    if (!this.enabled) return;

    this.agentService.updateState(iterationId, agentName, {
      status: 'completed',
      output: result,
      executionTimeSeconds: executionTime,
      completedAt: new Date()
    });

    // 广播进度更新
    this.realtimeService.broadcastIterationProgress({
      iterationId,
      agentName,
      progress: 100,
      message: `${agentName} 完成`,
      timestamp: new Date()
    });
  }

  /**
   * 迭代完成
   */
  async onIterationComplete(
    iterationId: number,
    results: Record<string, string>,
    commitInfo?: { hash: string; message: string; branch: string }
  ) {
    if (!this.enabled) return;

    this.iterationService.update(iterationId, {
      status: 'completed',
      completedAt: new Date(),
      ...results,
      ...commitInfo
    });

    // 广播完成事件
    this.realtimeService.broadcastIterationStatusChange({
      iterationId,
      status: 'completed',
      timestamp: new Date()
    });
  }

  /**
   * 迭代失败
   */
  async onIterationError(iterationId: number, error: Error) {
    if (!this.enabled) return;

    this.iterationService.update(iterationId, {
      status: 'failed',
      errorMessage: error.message,
      completedAt: new Date()
    });
  }
}
```

**阶段 2: 修改 AutoIterationEngine (2小时)**

```typescript
// src/auto-iteration.ts

import { IterationIntegration } from './dashboard/integration/iteration-integration';

export class AutoIterationEngine {
  private integration: IterationIntegration;

  constructor(config: AutoIterationConfig) {
    // ... 原有代码

    // 初始化 Dashboard 集成
    this.integration = new IterationIntegration();
  }

  async start() {
    while (this.running && this.shouldContinue()) {
      const iterationNum = this.iterationCount + 1;

      // 通知 Dashboard：迭代开始
      const iterationId = await this.integration.onIterationStart(
        iterationNum,
        this.requirement || '自动发现的需求'
      );

      try {
        // 1. 产品经理分析需求
        const pmAgent = this.createAgent('product-manager');
        await this.integration.onAgentStart(iterationId, '产品经理', '分析项目需求');
        const pmResult = await pmAgent.execute(this.requirement);
        await this.integration.onAgentComplete(iterationId, '产品经理', pmResult, ...);

        // 2. 架构师设计
        const architectAgent = this.createAgent('architect');
        await this.integration.onAgentStart(iterationId, '架构师', '设计系统架构');
        const architectResult = await architectAgent.execute(pmResult);
        await this.integration.onAgentComplete(iterationId, '架构师', architectResult, ...);

        // ... 其他 Agent 执行 ...

        // 迭代成功
        await this.integration.onIterationComplete(iterationId, {
          architectResult: architectResult,
          frontendResult: frontendResult,
          backendResult: backendResult,
          // ...
        }, {
          hash: commitHash,
          message: commitMessage,
          branch: currentBranch
        });

      } catch (error) {
        await this.integration.onIterationError(iterationId, error);
      }

      this.iterationCount++;
    }
  }
}
```

